input.command:
gh api graphql -f query='query { 
  squashTitle: __type(name: "SquashMergeCommitTitle") { 
    enumValues { name description } 
  }
  squashMessage: __type(name: "SquashMergeCommitMessage") {
    enumValues { name description }
  }
}' 2>&1

cat > /tmp/ruleset.json <<'EOF'
